if (
  binding &&
  t.isImportSpecifier(binding.path.node) &&
  t.isIdentifier(binding.path.node.imported)
) {
  return binding.path.node.imported.name;
}

while (true) {
  if (ts.isBindingElement(node.parent.parent)) {
    node = node.parent.parent;
  } else {
    return node.parent.parent;
  }
}

if (project.isClosed()) {
  this.info(`Cannot enable language service for closed project ${projectName}.`);
  return;
}

try {
  const eslint = await import('eslint');
  return eslint.ESLint;
} catch {
  throw new Error('Unable to find ESLint. Ensure ESLint is installed.');
}

if (toVersion.startsWith('custom input')) {
  toVersion = await input({
    default: 'master',
    message: `🔀 Please input custom git hash id or branch name to compare with ${chalk.magenta(
      finalFromVersion,
    )}:`,
  });
}

if (hasNamedCatalogs) {
  for (const [name, packages] of Object.entries(json.catalogs!)) {
    catalogs.push({ name, packages })
  }
}

for (const name of Object.keys(options.packageMode)) {
  const regex = filterToRegex(name)
  if (regex.test(pkgName))
    return options.packageMode[name]
}

if (value !== undefined) {
  // Move to end (most recently used)
  this.cache.delete(key)
  this.cache.set(key, value)
}

if ((json.access as string) === "private") {
  normalizedAccess = "restricted";
  warn(
    'The `access` option is set as "private", but this is actually not a valid value - the correct form is "restricted".'
  );
}

if (item instanceof Array)
      return cloneArray(item);
    else if (typeof item === "object")
      return item === null ? item : clone(item);

if (!swc) {
  logger.warn(
    build.initialOptions.format!,
    `You have emitDecoratorMetadata enabled but @swc/core was not installed, skipping swc plugin`,
  )
  return
}

if (!excludeDependents) {
  collectDependents(candidates, projectGraph).forEach((node) => (candidates[node.name] = node));
}

if (resizeObserverRef.current) {
  resizeObserverRef.current.disconnect();
  resizeObserverRef.current = null;
}

if (nextOption) {
  activeDescendantController.focus(nextOption.id);
} else {
  activeDescendantController.blur();
}

if (error) {
  for (const callback of this._saveCallbacks)
    await callback('', error);
} else {
  for (const callback of this._saveCallbacks)
    await callback(this._localPath);
}

if (node.d.chainedAnnotationComment) {
    this._addDiagnostic(
        DiagnosticRule.reportInvalidTypeForm,
        LocMessage.annotationNotSupported(),
        node.d.chainedAnnotationComment
    );
}

if (element.summary) {
  packageModel.summary = element.summary;
} else {
  packageModel.summary = '';
}

for (const key of arrayFrom(state.emitDiagnosticsPerFile.keys()).sort(compareStringsCaseSensitive)) {
    const value = state.emitDiagnosticsPerFile.get(key)!;
    result = append(result, [
        toFileId(key),
        toReusableDiagnostic(value, key),
    ]);
}

for (const array of arrays) {
	for (const item of array) {
		if (!includes(result, item)) {
			result.push(item);
		}
	}
}

if (diagonal >= 0 && diagonal < numDiagonals) {
	// Nothing to clip, its in range
	return diagonal;
}

if (!this.lsOptions.fileSystemProvider || !this.lsOptions.fileSystemProvider.readDirectory) {
	return this.doComplete(document, position, htmlDocument, settings);
}

if (formattingRange) {
	const offset = documentToFormat.offsetAt(formattingRange.start);
	const length = documentToFormat.offsetAt(formattingRange.end) - offset;
	range = { offset, length };
}

if (configurationOrTextDocuments instanceof TextDocuments) {
	this._cellTextDocuments = configurationOrTextDocuments;
} else {
	this._cellTextDocuments = new TextDocuments<T>(configurationOrTextDocuments);
}

for (const key of keys) {
	pendingValidationRequests[key].dispose();
	delete pendingValidationRequests[key];
}

if (shouldResolveAfterDraining) {
  subscription.unsubscribe();
  resolve();
} else if (shouldErrorAfterDraining) {
  call.emit('error', error);
  subscription.unsubscribe();
  resolve();
}

for (const projectName of Object.keys(nodes)) {
  const root = nodes[projectName].data.root;

  projectRootMappings.set(normalizeProjectRoot(root), projectName);
}

for (const permutation of validPermutations) {
  if (!this._commands.has(permutation)) {
    const cmd = this._commands.get(this.getCmdLookupId(permutation))!
    commands.push({...cmd, id: permutation})
  }
}

if (hasWorkspaceFolderCapability) {
  connection.workspace.onDidChangeWorkspaceFolders(_event => {
    connection.console.log('Workspace folder change event received.');
  });
}

if (request.authHeaderValue) {
  _request.authHeaderValue = hideAuthInformation(request.authHeaderValue)
}

for (const cache of this.cacheFiles) {
	// Remove if older than ~7 days
	if ((time - cache.time) > 7) {
		fs.promises.unlink(path.join(this.cacheDirectory, cache.fileName)).catch(noop);
	}
}
